UPDATE pet
name = #{name}, cover = #{cover}, detail = #{detail}, address = #{address}, age = #{age}, gender = #{gender}, pet_type_id = #{petTypeId}, is_vaccine = #{isVaccine}, is_recommend = #{isRecommend}, is_adopt = #{isAdopt},
