mapper.select:
SELECT p.id, p.name, p.cover, p.address, p.age, p.gender, p.pet_type_id, p.is_vaccine, p.is_recommend, p.is_adopt, p.create_time, pt.name AS pet_type_name FROM pet p LEFT JOIN pet_type pt ON pt.id = p.pet_type_id
AND p.name LIKE concat('%',#{name},'%')
AND p.is_recommend = #{isRecommend}
AND p.pet_type_id = #{petTypeId}
LIMIT #{current},#{size}

SELECT COUNT(*)
FROM pet p


        AND p.name LIKE concat('%',#{name},'%')


        AND p.is_recommend = #{isRecommend}


        AND p.pet_type_id = #{petTypeId}

SELECT pt.id, pt.name
FROM pet pt
WHERE pt.name = #{name}
